import json, pathlib, threading

class FileKVMemory:
    """Thread-safe key-value memory backed by a local JSONL file."""

    def __init__(self, path: str) -> None:
        self._path = pathlib.Path(path)
        self._lock = threading.Lock()
        self._data: dict[str, object] = {}
        self._load()

    def _load(self) -> None:
        if self._path.exists():
            with open(self._path) as f:
                for line in f:
                    line = line.strip()
                    if line:
                        entry = json.loads(line)
                        self._data[entry["key"]] = entry["value"]

    def get(self, key: str, default=None):
        return self._data.get(key, default)

    def set(self, key: str, value) -> None:
        with self._lock:
            self._data[key] = value
            # Append-only write; reload periodically to compact
            with open(self._path, "a") as f:
                f.write(json.dumps({"key": key, "value": value}) + "\n")

    def delete(self, key: str) -> None:
        with self._lock:
            self._data.pop(key, None)
            # Rewrite entire file without deleted key
            with open(self._path, "w") as f:
                for k, v in self._data.items():
                    f.write(json.dumps({"key": k, "value": v}) + "\n")

    def keys(self) -> list[str]:
        return list(self._data.keys())


# Usage
mem = FileKVMemory("memory/user_prefs.jsonl")
mem.set("user:alice:language", "fr")
mem.set("user:alice:timezone", "Europe/Paris")
print(mem.get("user:alice:language"))   # "fr"

from dataclasses import dataclass

@dataclass
class MemoryManager:
    kv: FileKVMemory
    db: sqlite3.Connection   # managed externally
    # vector: SimpleVectorMemory  # add when embeddings are available

    def remember(self, user_id: str, fact: str, category: str = "fact") -> None:
        """Persist a new fact for a user."""
        save_memory(user_id, category, fact)

    def recall(self, user_id: str, query: str, top_k: int = 5) -> list[str]:
        """Return the most relevant stored facts for a query."""
        # Exact-category lookup first
        rows = recall_memories(user_id, limit=top_k * 2)
        # Simple keyword filter as a stand-in for semantic search
        query_words = set(query.lower().split())
        scored = []
        for row in rows:
            content_words = set(row["content"].lower().split())
            overlap = len(query_words & content_words)
            if overlap > 0:
                scored.append((overlap, row["content"]))
        scored.sort(reverse=True)
        return [c for _, c in scored[:top_k]]

    def get_pref(self, user_id: str, key: str, default=None):
        return self.kv.get(f"{user_id}:{key}", default)

    def set_pref(self, user_id: str, key: str, value) -> None:
        self.kv.set(f"{user_id}:{key}", value)

    def inject_into_prompt(self, user_id: str, query: str) -> str:
        """Build a memory injection block for the system prompt."""
        prefs  = {k.split(":")[-1]: self.kv.get(k) for k in self.kv.keys() if k.startswith(f"{user_id}:")}
        facts  = self.recall(user_id, query)
        lines  = []
        if prefs:
            lines.append("[USER PREFERENCES]")
            lines.extend(f"  {k}: {v}" for k, v in prefs.items())
        if facts:
            lines.append("[RELEVANT MEMORY]")
            lines.extend(f"  - {f}" for f in facts)
        return "\n".join(lines)
